typedef struct pub_cl { \n\
  int tSize, sSize, maxMove, frame_no, frames, frame_rows, frame_cols; \n\
  int in2_rows, in2_cols, in_mod_rows, in_mod_cols, in_mod_elem, conv_rows, conv_cols; \n\
