  int in2_pad_cumv_sel2_rowlow, in2_pad_cumv_sel2_rowhig, in2_pad_cumv_sel2_collow, in2_pad_cumv_sel2_colhig; \n\
  int in2_sub_rows, in2_sub_cols, in2_sub_elem; \n\
  int in2_sub_cumh_sel_rowlow, in2_sub_cumh_sel_rowhig, in2_sub_cumh_sel_collow, in2_sub_cumh_sel_colhig; \n\
  int in2_sub_cumh_sel2_rowlow, in2_sub_cumh_sel2_rowhig, in2_sub_cumh_sel2_collow, in2_sub_cumh_sel2_colhig; \n\
  int in2_sub2_sqr_rows, in2_sub2_sqr_cols; \n\
  int tMask_rows, tMask_cols, tMask_elem; \n\
  int mask_rows, mask_cols, mask_conv_rows, mask_conv_cols, mask_conv_elem, mask_conv_ioffset, mask_conv_joffset; \n\
