} pub_cl; \n\
\n\
kernel void heartwall_kernel( \n\
  pub_cl p, \n\
  global const int* dR, global const int* dC, \n\
  global int* dTRL, global int* dTCL, \n\
  global fp* dT, \n\
  global fp* dF, \n\
  global fp* d2, global fp* d2s, \n\
  global fp* dm, global fp* ds, \n\
  global fp* dc, \n\
  global fp* dp, \n\
  global fp* dsu, \n\
  global fp* d2sq, \n\
  global fp* tm, \n\
  global fp* mc, \n\
  int pn, int ip) \n\
{ \n\
  fp temp, temp2, s, sum, ifs, isfs, mean, ms, var, dev, den; \n\
  int c, r, or, oc, op, ptr, rr, rc; \n\
  int ja1, ja2, ia1, ia2, ja, jb, ia, ib, jp1, ip1, i, j; \n\
  int ei, po, pos; \n\
  fp fmv; int fmc, lr, lc, ofr, ofc, cent, tmr, tmc, lp; \n\
  int irl = dR[pn] - p.sSize; \n\
  int icl = dC[pn] - p.sSize; \n\
\n\
  if (p.frame_no == 0) { \n\
    ptr = pn * p.frames + p.frame_no; \n\
    dTRL[ptr] = dR[pn]; \n\
    dTCL[ptr] = dC[pn]; \n\
    fp* di = dT + ip; \n\
    for (c = 0; c < p.in_mod_cols; c++) { \n\
      for (r = 0; r < p.in_mod_rows; r++) { \n\
        or = dR[pn] - 25 + r - 1; \n\
        oc = dC[pn] - 25 + c - 1; \n\
        di[c * p.in_mod_rows + r] = dF[oc * p.frame_rows + or]; \n\
      } \n\
    } \n\
  } \n\
\n\
  if (p.frame_no != 0) { \n\
    for (c = 0; c < p.in2_cols; c++) { \n\
      for (r = 0; r < p.in2_rows; r++) { \n\
        or = r + irl - 1; \n\
        oc = c + icl - 1; \n\
        temp = dF[oc * p.frame_rows + or]; \n\
        d2[c * p.in2_rows + r] = temp; \n\
        d2s[c * p.in2_rows + r] = temp * temp; \n\
      } \n\
    } \n\
    fp* di = dT + ip; \n\
    for (c = 0; c < p.in_mod_cols; c++) { \n\
      for (r = 0; r < p.in_mod_rows; r++) { \n\
        rr = (p.in_mod_rows - 1) - r; \n\
        rc = (p.in_mod_rows - 1) - c; \n\
        ptr = rc * p.in_mod_rows + rr; \n\
        temp = di[ptr]; \n\
        dm[c * p.in_mod_rows + r] = temp; \n\
        ds[ptr] = temp * temp; \n\
      } \n\
    } \n\
    ifs = 0; isfs = 0; \n\
    for (i = 0; i < p.in_mod_elem; i++) { ifs += di[i]; isfs += ds[i]; } \n\
    mean = ifs / p.in_mod_elem; \n\
    ms = mean * mean; \n\
    var = (isfs / p.in_mod_elem) - ms; \n\
    dev = sqrt(var); \n\
    den = sqrt((fp)(p.in_mod_elem - 1)) * dev; \n\
\n\
    for (c = 1; c <= p.conv_cols; c++) { \n\
      j = c + p.joffset; jp1 = j + 1; \n\
      ja1 = (p.in2_cols < jp1) ? (jp1 - p.in2_cols) : 1; \n\
      ja2 = (p.in_mod_cols < j) ? p.in_mod_cols : j; \n\
      for (r = 1; r <= p.conv_rows; r++) { \n\
        i = r + p.ioffset; ip1 = i + 1; \n\
        ia1 = (p.in2_rows < ip1) ? (ip1 - p.in2_rows) : 1; \n\
        ia2 = (p.in_mod_rows < i) ? p.in_mod_rows : i; \n\
        s = 0; \n\
        for (ja = ja1; ja <= ja2; ja++) { \n\
          jb = jp1 - ja; \n\
          for (ia = ia1; ia <= ia2; ia++) { \n\
            ib = ip1 - ia; \n\
            s += dm[p.in_mod_rows * (ja - 1) + ia - 1] * d2[p.in2_rows * (jb - 1) + ib - 1]; \n\
          } \n\
        } \n\
        dc[(c - 1) * p.conv_rows + (r - 1)] = s; \n\
      } \n\
    } \n\
\n\
    for (c = 0; c < p.in2_pad_cols; c++) { \n\
      for (r = 0; r < p.in2_pad_rows; r++) { \n\
        if (r > (p.in2_pad_add_rows - 1) && r < (p.in2_pad_add_rows + p.in2_rows) && \n\
            c > (p.in2_pad_add_cols - 1) && c < (p.in2_pad_add_cols + p.in2_cols)) { \n\
          or = r - p.in2_pad_add_rows; oc = c - p.in2_pad_add_cols; \n\
          dp[c * p.in2_pad_rows + r] = d2[oc * p.in2_rows + or]; \n\
        } else { dp[c * p.in2_pad_rows + r] = 0; } \n\
      } \n\
    } \n\
    for (ei = 0; ei < p.in2_pad_cols; ei++) { \n\
      po = ei * p.in2_pad_rows; sum = 0; \n\
      for (pos = po; pos < po + p.in2_pad_rows; pos++) { dp[pos] += sum; sum = dp[pos]; } \n\
    } \n\
    for (c = 0; c < p.in2_sub_cols; c++) { \n\
      for (r = 0; r < p.in2_sub_rows; r++) { \n\
        or = r + p.in2_pad_cumv_sel_rowlow - 1; oc = c + p.in2_pad_cumv_sel_collow - 1; \n\
        temp = dp[oc * p.in2_pad_rows + or]; \n\
        or = r + p.in2_pad_cumv_sel2_rowlow - 1; oc = c + p.in2_pad_cumv_sel2_collow - 1; \n\
        temp2 = dp[oc * p.in2_pad_rows + or]; \n\
        dsu[c * p.in2_sub_rows + r] = temp - temp2; \n\
      } \n\
    } \n\
    for (ei = 0; ei < p.in2_sub_rows; ei++) { \n\
      po = ei; sum = 0; \n\
      for (pos = po; pos < po + p.in2_sub_elem; pos += p.in2_sub_rows) { dsu[pos] += sum; sum = dsu[pos]; } \n\
    } \n\
    for (c = 0; c < p.in2_sub2_sqr_cols; c++) { \n\
      for (r = 0; r < p.in2_sub2_sqr_rows; r++) { \n\
        or = r + p.in2_sub_cumh_sel_rowlow - 1; oc = c + p.in2_sub_cumh_sel_collow - 1; \n\
        temp = dsu[oc * p.in2_sub_rows + or]; \n\
        or = r + p.in2_sub_cumh_sel2_rowlow - 1; oc = c + p.in2_sub_cumh_sel2_collow - 1; \n\
        temp2 = dsu[oc * p.in2_sub_rows + or]; \n\
        temp2 = temp - temp2; \n\
        d2sq[c * p.in2_sub2_sqr_rows + r] = temp2 * temp2; \n\
        dc[c * p.in2_sub2_sqr_rows + r] -= temp2 * ifs / p.in_mod_elem; \n\
      } \n\
    } \n\
\n\
    for (c = 0; c < p.in2_pad_cols; c++) { \n\
      for (r = 0; r < p.in2_pad_rows; r++) { \n\
        if (r > (p.in2_pad_add_rows - 1) && r < (p.in2_pad_add_rows + p.in2_rows) && \n\
            c > (p.in2_pad_add_cols - 1) && c < (p.in2_pad_add_cols + p.in2_cols)) { \n\
          or = r - p.in2_pad_add_rows; oc = c - p.in2_pad_add_cols; \n\
          dp[c * p.in2_pad_rows + r] = d2s[oc * p.in2_rows + or]; \n\
        } else { dp[c * p.in2_pad_rows + r] = 0; } \n\
      } \n\
    } \n\
    for (ei = 0; ei < p.in2_pad_cols; ei++) { \n\
      po = ei * p.in2_pad_rows; sum = 0; \n\
      for (pos = po; pos < po + p.in2_pad_rows; pos++) { dp[pos] += sum; sum = dp[pos]; } \n\
    } \n\
    for (c = 0; c < p.in2_sub_cols; c++) { \n\
      for (r = 0; r < p.in2_sub_rows; r++) { \n\
        or = r + p.in2_pad_cumv_sel_rowlow - 1; oc = c + p.in2_pad_cumv_sel_collow - 1; \n\
        temp = dp[oc * p.in2_pad_rows + or]; \n\
        or = r + p.in2_pad_cumv_sel2_rowlow - 1; oc = c + p.in2_pad_cumv_sel2_collow - 1; \n\
        temp2 = dp[oc * p.in2_pad_rows + or]; \n\
        dsu[c * p.in2_sub_rows + r] = temp - temp2; \n\
      } \n\
    } \n\
    for (ei = 0; ei < p.in2_sub_rows; ei++) { \n\
      po = ei; sum = 0; \n\
      for (pos = po; pos < po + p.in2_sub_elem; pos += p.in2_sub_rows) { dsu[pos] += sum; sum = dsu[pos]; } \n\
    } \n\
    for (c = 0; c < p.conv_cols; c++) { \n\
      for (r = 0; r < p.conv_rows; r++) { \n\
        or = r + p.in2_sub_cumh_sel_rowlow - 1; oc = c + p.in2_sub_cumh_sel_collow - 1; \n\
        temp = dsu[oc * p.in2_sub_rows + or]; \n\
        or = r + p.in2_sub_cumh_sel2_rowlow - 1; oc = c + p.in2_sub_cumh_sel2_collow - 1; \n\
        temp2 = dsu[oc * p.in2_sub_rows + or]; \n\
        temp2 = temp - temp2; \n\
        temp2 = temp2 - (d2sq[c * p.conv_rows + r] / p.in_mod_elem); \n\
        if (temp2 < 0) temp2 = 0; \n\
        temp2 = sqrt(temp2); \n\
        temp2 = den * temp2; \n\
        dc[c * p.conv_rows + r] /= temp2; \n\
      } \n\
    } \n\
\n\
    cent = p.sSize + p.tSize + 1; \n\
    ptr = p.frame_no - 1 + pn * p.frames; \n\
    tmr = cent + dTRL[ptr] - dR[pn] - 1; \n\
    tmc = cent + dTCL[ptr] - dC[pn] - 1; \n\
    for (ei = 0; ei < p.tMask_elem; ei++) tm[ei] = 0; \n\
    tm[tmc * p.tMask_rows + tmr] = 1; \n\
\n\
    for (c = 1; c <= p.mask_conv_cols; c++) { \n\
      j = c + p.mask_conv_joffset; jp1 = j + 1; \n\
      ja1 = (p.mask_cols < jp1) ? (jp1 - p.mask_cols) : 1; \n\
      ja2 = (p.tMask_cols < j) ? p.tMask_cols : j; \n\
      for (r = 1; r <= p.mask_conv_rows; r++) { \n\
        i = r + p.mask_conv_ioffset; ip1 = i + 1; \n\
        ia1 = (p.mask_rows < ip1) ? (ip1 - p.mask_rows) : 1; \n\
        ia2 = (p.tMask_rows < i) ? p.tMask_rows : i; \n\
        s = 0; \n\
        for (ja = ja1; ja <= ja2; ja++) { \n\
          jb = jp1 - ja; \n\
          for (ia = ia1; ia <= ia2; ia++) { \n\
            ib = ip1 - ia; \n\
            s += tm[p.tMask_rows * (ja - 1) + ia - 1] * 1; \n\
          } \n\
        } \n\
        mc[(c - 1) * p.conv_rows + (r - 1)] = dc[(c - 1) * p.conv_rows + (r - 1)] * s; \n\
      } \n\
    } \n\
\n\
    fmv = 0; fmc = 0; \n\
    for (i = 0; i < p.mask_conv_elem; i++) { \n\
      if (mc[i] > fmv) { fmv = mc[i]; fmc = i; } \n\
    } \n\
    lr = (fmc + 1) % p.mask_conv_rows - 1; \n\
    lc = (fmc + 1) / p.mask_conv_rows; \n\
    if ((fmc + 1) % p.mask_conv_rows == 0) { lr = p.mask_conv_rows - 1; lc--; } \n\
    lr++; lc++; \n\
    ofr = lr - p.in_mod_rows - (p.sSize - p.tSize); \n\
    ofc = lc - p.in_mod_cols - (p.sSize - p.tSize); \n\
    ptr = pn * p.frames + p.frame_no; \n\
    dTRL[ptr] = dR[pn] + ofr; \n\
    dTCL[ptr] = dC[pn] + ofc; \n\
  } \n\
\n\
  if (p.frame_no != 0 && (p.frame_no % 10 == 0)) { \n\
    lp = pn * p.frames + p.frame_no; \n\
    dR[pn] = dTRL[lp]; \n\
    dC[pn] = dTCL[lp]; \n\
    fp* di = dT + ip; \n\
    for (c = 0; c < p.in_mod_cols; c++) { \n\
      for (r = 0; r < p.in_mod_rows; r++) { \n\
        or = dR[pn] - 25 + r - 1; \n\
        oc = dC[pn] - 25 + c - 1; \n\
        op = oc * p.frame_rows + or; \n\
        di[c * p.in_mod_rows + r] = p.alpha * di[c * p.in_mod_rows + r] + (1.00 - p.alpha) * dF[op]; \n\
      } \n\
    } \n\
  } \n\
} \n\
";

void check_cl(cl_int err) {
    if (err != CL_SUCCESS) {
        fprintf(stderr, "OpenCL Error: %d\n", err);
        exit(1);
    }
}

int main(int argc, char** argv) {
    // Default parameters
