    int in_mod_elem = in_mod_rows * in_mod_cols;
    int in2_rows = 2 * sSize + 1; // 81
    int in2_cols = in2_rows;
    int conv_rows = in_mod_rows + in2_rows - 1; // 131
    int conv_cols = in_mod_cols + in2_cols - 1;
    int in2_pad_add_rows = in_mod_rows;
    int in2_pad_add_cols = in_mod_cols;
    int in2_pad_rows = in2_rows + 2 * in2_pad_add_rows;
    int in2_pad_cols = in2_cols + 2 * in2_pad_add_cols;
    int in2_sub_rows = in2_pad_rows - in_mod_rows - 1; // Derived logic
    int in2_sub_cols = in2_pad_cols;
