    int mask_conv_rows = tMask_rows;
    int mask_conv_cols = tMask_cols;

    // Create Buffers
    cl_mem buf_endoRow = cl_create_buffer(context, CL_MEM_COPY_HOST_PTR, sizeof(int) * endoPoints, endoRow, &err);
    cl_mem buf_endoCol = cl_create_buffer(context, CL_MEM_COPY_HOST_PTR, sizeof(int) * endoPoints, endoCol, &err);
    cl_mem buf_tEndoRowLoc = cl_create_buffer(context, CL_MEM_COPY_HOST_PTR, sizeof(int) * endoPoints * no_frames, tEndoRowLoc, &err);
