    cl_mem buf_in2 = cl_create_buffer(context, CL_MEM_ALLOC_HOST_PTR, sizeof(fp) * in2_rows * in2_cols, NULL, &err);
    cl_mem buf_in2s = cl_create_buffer(context, CL_MEM_ALLOC_HOST_PTR, sizeof(fp) * in2_rows * in2_cols, NULL, &err);
