    cl_mem buf_dsu = cl_create_buffer(context, CL_MEM_ALLOC_HOST_PTR, sizeof(fp) * in2_sub_rows * in2_sub_cols, NULL, &err);
    cl_mem buf_d2sq = cl_create_buffer(context, CL_MEM_ALLOC_HOST_PTR, sizeof(fp) * in2_sub_rows * in2_sub_cols, NULL, &err);
    cl_mem buf_tm = cl_create_buffer(context, CL_MEM_ALLOC_HOST_PTR, sizeof(fp) * tMask_rows * tMask_cols, NULL, &err);
    cl_mem buf_mc = cl_create_buffer(context, CL_MEM_ALLOC_HOST_PTR, sizeof(fp) * mask_conv_rows * mask_conv_cols, NULL, &err);

    // Print start message
    printf("frame progress: ");
    fflush(stdout);

    // Frame Loop
    for (int frame_no = 0; frame_no < frames_processed; frame_no++) {
        fp* d_frame = get_frame(frames, frame_no, 0, 0, 1);
        cl_write_buffer(buf_frame, CL_TRUE, 0, sizeof(fp) * frame_elem, d_frame, NULL, NULL, NULL);
        free(d_frame);

        // Prepare public struct for kernel
        typedef struct {
            int tSize, sSize, maxMove, frame_no, frames, frame_rows, frame_cols;
            int in2_rows, in2_cols, in_mod_rows, in_mod_cols, in_mod_elem, conv_rows, conv_cols;
            int ioffset, joffset, in2_pad_add_rows, in2_pad_add_cols, in2_pad_rows, in2_pad_cols;
            int in2_pad_cumv_sel_rowlow, in2_pad_cumv_sel_rowhig, in2_pad_cumv_sel_collow, in2_pad_cumv_sel_colhig;
            int in2_pad_cumv_sel2_rowlow, in2_pad_cumv_sel2_rowhig, in2_pad_cumv_sel2_collow, in2_pad_cumv_sel2_colhig;
            int in2_sub_rows, in2_sub_cols, in2_sub_elem;
            int in2_sub_cumh_sel_rowlow, in2_sub_cumh_sel_rowhig, in2_sub_cumh_sel_collow, in2_sub_cumh_sel_colhig;
            int in2_sub_cumh_sel2_rowlow, in2_sub_cumh_sel2_rowhig, in2_sub_cumh_sel2_collow, in2_sub_cumh_sel2_colhig;
            int in2_sub2_sqr_rows, in2_sub2_sqr_cols;
            int tMask_rows, tMask_cols, tMask_elem;
            int mask_rows, mask_cols, mask_conv_rows, mask_conv_cols, mask_conv_elem, mask_conv_ioffset, mask_conv_joffset;
            fp alpha;
        } pub_cl;

        pub_cl p;
        p.tSize = tSize; p.sSize = sSize; p.maxMove = maxMove; p.alpha = alpha;
        p.frame_no = frame_no; p.frames = no_frames;
        p.frame_rows = frame_rows; p.frame_cols = frame_cols;
        p.in2_rows = in2_rows; p.in2_cols = in2_cols;
        p.in_mod_rows = in_mod_rows; p.in_mod_cols = in_mod_cols; p.in_mod_elem = in_mod_elem;
        p.conv_rows = conv_rows; p.conv_cols = conv_cols;
        p.ioffset = 0; p.joffset = 0;
        p.in2_pad_add_rows = in2_pad_add_rows; p.in2_pad_add_cols = in2_pad_add_cols;
        p.in2_pad_rows = in2_pad_rows; p.in2_pad_cols = in2_pad_cols;
        p.in2_pad_cumv_sel_rowlow = 1 + in_mod_rows;
        p.in2_pad_cumv_sel_rowhig = in2_pad_rows - 1;
        p.in2_pad_cumv_sel_collow = 1;
        p.in2_pad_cumv_sel_colhig = in2_pad_cols;
        p.in2_pad_cumv_sel2_rowlow = 1;
        p.in2_pad_cumv_sel2_rowhig = in2_pad_rows - in_mod_rows - 1;
        p.in2_pad_cumv_sel2_collow = 1;
        p.in2_pad_cumv_sel2_colhig = in2_pad_cols;
        p.in2_sub_rows = p.in2_pad_cumv_sel_rowhig - p.in2_pad_cumv_sel_rowlow + 1;
        p.in2_sub_cols = p.in2_pad_cumv_sel_colhig - p.in2_pad_cumv_sel_collow + 1;
        p.in2_sub_elem = p.in2_sub_rows * p.in2_sub_cols;
        p.in2_sub_cumh_sel_rowlow = 1;
        p.in2_sub_cumh_sel_rowhig = p.in2_sub_rows;
        p.in2_sub_cumh_sel_collow = 1 + in_mod_cols;
        p.in2_sub_cumh_sel_colhig = p.in2_sub_cols - 1;
        p.in2_sub_cumh_sel2_rowlow = 1;
        p.in2_sub_cumh_sel2_rowhig = p.in2_sub_rows;
        p.in2_sub_cumh_sel2_collow = 1;
        p.in2_sub_cumh_sel2_colhig = p.in2_sub_cols - in_mod_cols - 1;
        p.in2_sub2_sqr_rows = p.in2_sub_cumh_sel_rowhig - p.in2_sub_cumh_sel_rowlow + 1;
        p.in2_sub2_sqr_cols = p.in2_sub_cumh_sel_colhig - p.in2_sub_cumh_sel_collow + 1;
        p.tMask_rows = tMask_rows; p.tMask_cols = tMask_cols; p.tMask_elem = tMask_rows * tMask_cols;
        p.mask_rows = maxMove; p.mask_cols = maxMove;
        p.mask_conv_rows = mask_conv_rows; p.mask_conv_cols = mask_conv_cols;
        p.mask_conv_elem = mask_conv_rows * mask_conv_cols;
        p.mask_conv_ioffset = (p.mask_rows - 1) / 2;
        if ((p.mask_rows - 1) % 2 > 0.5) p.mask_conv_ioffset++;
        p.mask_conv_joffset = (p.mask_cols - 1) / 2;
        if ((p.mask_cols - 1) % 2 > 0.5) p.mask_conv_joffset++;

        // Execute for each point (Endo only for this example loop, Epi similar)
        for (int pt = 0; pt < endoPoints; pt++) {
            int ip = pt * in_mod_elem;
            cl_set_kernel_arg(kernel, 0, sizeof(pub_cl), &p);
            cl_set_kernel_arg(kernel, 1, sizeof(cl_mem), &buf_endoRow);
            cl_set_kernel_arg(kernel, 2, sizeof(cl_mem), &buf_endoCol);
            cl_set_kernel_arg(kernel, 3, sizeof(cl_mem), &buf_tEndoRowLoc);
            cl_set_kernel_arg(kernel, 4, sizeof(cl_mem), &buf_tEndoColLoc);
            cl_set_kernel_arg(kernel, 5, sizeof(cl_mem), &buf_endoT);
            cl_set_kernel_arg(kernel, 6, sizeof(cl_mem), &buf_frame);
            cl_set_kernel_arg(kernel, 7, sizeof(cl_mem), &buf_in2);
            cl_set_kernel_arg(kernel, 8, sizeof(cl_mem), &buf_in2s);
            cl_set_kernel_arg(kernel, 9, sizeof(cl_mem), &buf_dm);
            cl_set_kernel_arg(kernel, 10, sizeof(cl_mem), &buf_ds);
            cl_set_kernel_arg(kernel, 11, sizeof(cl_mem), &buf_dc);
            cl_set_kernel_arg(kernel, 12, sizeof(cl_mem), &buf_dp);
            cl_set_kernel_arg(kernel, 13, sizeof(cl_mem), &buf_dsu);
            cl_set_kernel_arg(kernel, 14, sizeof(cl_mem), &buf_d2sq);
            cl_set_kernel_arg(kernel, 15, sizeof(cl_mem), &buf_tm);
            cl_set_kernel_arg(kernel, 16, sizeof(cl_mem), &buf_mc);
            cl_set_kernel_arg(kernel, 17, sizeof(int), &pt);
            cl_set_kernel_arg(kernel, 18, sizeof(int), &ip);

            size_t global_size = 1;
            cl_enqueue_task(queue, kernel, 1, &global_size, NULL, NULL);
        }
        cl_finish(queue);

        printf("%d ", frame_no);
        fflush(stdout);
    }
    printf("\n");

    // Read back results
    cl_read_buffer(buf_tEndoRowLoc, CL_TRUE, 0, sizeof(int) * endoPoints * no_frames, tEndoRowLoc, NULL, NULL, NULL);
    cl_read_buffer(buf_tEndoColLoc, CL_TRUE, 0, sizeof(int) * endoPoints * no_frames, tEndoColLoc, NULL, NULL, NULL);

    // Cleanup
    free(endoRow); free(endoCol); free(tEndoRowLoc); free(tEndoColLoc);
    free(epiRow); free(epiCol); free(tEpiRowLoc); free(tEpiColLoc);
    AVI_close(frames);

    cl_release_kernel(kernel);
    cl_release_program(program);
    cl_release_command_queue(queue);
    cl_release_context(context);

    return 0;
}
